-- Barbell
('Reverse Barbell Curl', 'Biceps', 'Hold a barbell with an overhand (pronated) grip. Curl the bar up by flexing at the elbows. This targets the brachioradialis and forearms in addition to the biceps. Lower under control.', 'Barbell', ARRAY['Forearms'], 'intermediate', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Wide-Grip Barbell Curl', 'Biceps', 'Grip the barbell wider than shoulder-width. Curl up, keeping elbows pinned to your sides. The wider grip shifts emphasis to the short (inner) head of the bicep. Squeeze at the top.', 'Barbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Drag Curl', 'Biceps', 'Hold a barbell with a shoulder-width grip. Curl the bar by dragging it up along your body, pulling elbows back behind you. The bar should stay in contact with your torso. This emphasizes the long head of the bicep.', 'Barbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cheat Curl', 'Biceps', 'Use a slight hip swing to initiate a heavy barbell curl past the sticking point, then control the eccentric (lowering) phase for 3-4 seconds. The overloaded negative builds strength beyond what strict curls allow.', 'Barbell', ARRAY['Forearms','Core'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Preacher Curl', 'Biceps', 'Sit at a preacher bench and curl a barbell from full arm extension to peak contraction. The pad prevents you from swinging and isolates the biceps through the entire range of motion.', 'Barbell', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Cross-Body Hammer Curl', 'Biceps', 'Hold a dumbbell in each hand with a neutral grip. Curl one dumbbell across your body toward the opposite shoulder. This targets the brachialis and the long head of the bicep. Alternate arms.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Zottman Curl', 'Biceps', 'Curl dumbbells up with a supinated (palms-up) grip. At the top, rotate to a pronated (palms-down) grip and lower slowly. This trains both the biceps on the way up and the forearms on the way down.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Drag Curl', 'Biceps', 'Hold dumbbells at your sides. Curl them by dragging them up your body, pulling your elbows behind you. The dumbbells should stay close to your torso. Squeeze the long head of the bicep at the top.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Seated Alternating Dumbbell Curl', 'Biceps', 'Sit on a bench with dumbbells at your sides. Curl one arm at a time, supinating your wrist as you lift. The seated position prevents body English and keeps the focus on the biceps.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Standing Alternating Dumbbell Curl', 'Biceps', 'Stand with dumbbells at your sides. Curl one arm up while the other stays at your side. Alternate arms each rep. Keep your torso upright and elbows pinned to your sides.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Reverse Curl', 'Biceps', 'Hold dumbbells with a pronated (palms-down) grip. Curl up, keeping the overhand grip throughout. This heavily targets the brachioradialis and forearm extensors alongside the biceps.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Pinwheel Curl', 'Biceps', 'Hold a dumbbell in each hand with a neutral grip. Curl both dumbbells across your body simultaneously toward your opposite shoulders, creating a cross-body motion. This hammers the brachialis.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Slow Eccentric Dumbbell Curl', 'Biceps', 'Curl dumbbells up at normal speed, then lower them over 4-5 seconds. The extended time under tension during the eccentric phase stimulates more muscle damage and growth. Use a lighter weight than normal curls.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Machine Bicep Curl', 'Biceps', 'Sit in a bicep curl machine with your elbows on the pad. Curl the handle toward your shoulders, squeezing the biceps at the top. Lower with control. The machine provides consistent resistance throughout.', 'Machine', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Machine Preacher Curl', 'Biceps', 'Sit at a machine preacher curl station with your upper arms on the pad. Curl the handle to full contraction. The machine eliminates momentum and isolates the biceps completely.', 'Machine', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Machine Hammer Curl', 'Biceps', 'Use a machine with neutral-grip handles. Curl with palms facing each other, targeting the brachialis and brachioradialis in addition to the biceps. Squeeze at the top.', 'Machine', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Iso-Lateral Machine Curl', 'Biceps', 'Use a machine with independent arms. Curl one arm at a time or both together. Independent arms prevent your stronger arm from doing more work than your weaker arm.', 'Machine', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Single-Arm Cable Curl', 'Biceps', 'Attach a handle to a low cable. Stand facing the machine and curl one arm at a time. Cables provide constant tension — there''s no rest at the top or bottom unlike free weights.', 'Cable', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Hammer Curl', 'Biceps', 'Attach a rope to a low cable. Curl with a neutral (hammer) grip, keeping the rope ends apart. Squeeze the brachialis at the top. The cable provides constant tension throughout.', 'Cable', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Overhead Cable Curl', 'Biceps', 'Set both cables high with handles. Stand between them and curl the handles toward your head with arms outstretched, like a double bicep pose. Squeeze hard at the peak. Great for the bicep peak.', 'Cable', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Preacher Curl', 'Biceps', 'Set a cable low and use a preacher bench. Curl the handle from full extension to peak contraction. The cable provides constant tension even at the top where dumbbells lose resistance.', 'Cable', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Reverse Curl', 'Biceps', 'Attach a straight bar to a low cable. Curl with an overhand (pronated) grip, targeting the brachioradialis and forearms. The constant cable tension makes this harder than the barbell version.', 'Cable', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- TRICEPS (~25 new exercises)
-- ============================================================

-- Barbell
('Close-Grip Floor Press', 'Triceps', 'Lie on the floor with a narrow grip on the barbell. Lower until your triceps touch the floor, pause, then press up. The limited ROM and close grip isolate the triceps and lockout strength.', 'Barbell', ARRAY['Chest','Shoulders'], 'push', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Tricep Extension', 'Triceps', 'Stand or sit holding a barbell overhead with a shoulder-width grip. Lower the bar behind your head by bending at the elbows. Extend back to lockout. Keep your elbows pointing forward throughout.', 'Barbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Reverse-Grip Bench Press', 'Triceps', 'Lie on a flat bench and grip the barbell with an underhand (supinated) grip. Lower to the lower chest and press up. The reverse grip shifts significant emphasis to the triceps and upper chest.', 'Barbell', ARRAY['Chest','Shoulders'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Rolling Tricep Extension', 'Triceps', 'Lie on a bench with a barbell. Lower the bar behind your head like a skull crusher, but let the bar travel back and the elbows roll back slightly before reversing and pressing up. This adds a stretch component.', 'Barbell', ARRAY[]::text[], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Two-Arm Overhead Dumbbell Extension', 'Triceps', 'Hold one dumbbell with both hands overhead. Lower it behind your head by bending at the elbows. Extend back to lockout. Keep your elbows close to your head and pointing forward.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Single-Arm Overhead Dumbbell Extension', 'Triceps', 'Hold one dumbbell overhead with one arm. Lower it behind your head by bending the elbow. Extend back to lockout. This unilateral movement reveals and corrects strength imbalances.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Lying Dumbbell Tricep Extension', 'Triceps', 'Lie on a bench with dumbbells held overhead. Lower the dumbbells toward your temples by bending at the elbows. Extend back to lockout. Using dumbbells allows independent arm movement.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Tate Press', 'Triceps', 'Lie on a bench with dumbbells held with an overhand grip. Lower the dumbbells inward toward your chest by bending at the elbows, then press back up. The inward motion uniquely targets the triceps.', 'Dumbbell', ARRAY['Chest'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Floor Press (Tricep Focus)', 'Triceps', 'Lie on the floor with dumbbells. Press with a neutral or close grip, lowering until your triceps touch the floor. The limited range of motion focuses the work on the triceps lockout.', 'Dumbbell', ARRAY['Chest','Shoulders'], 'push', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Machine Tricep Dip', 'Triceps', 'Sit in an assisted or plate-loaded dip machine. Press down to full arm extension, focusing on squeezing the triceps at the bottom. Return with control. Keep your torso upright to focus on triceps.', 'Machine', ARRAY['Chest','Shoulders'], 'push', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Machine Tricep Extension', 'Triceps', 'Sit in a tricep extension machine with elbows on the pad. Extend your arms to lockout, squeezing the triceps. Return under control. The machine provides consistent resistance throughout.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Iso-Lateral Tricep Machine', 'Triceps', 'Use a machine with independent arms. Extend one arm at a time or both together. Independent arms ensure both triceps work equally and reveal any imbalances.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Assisted Dip Machine (Tricep Focus)', 'Triceps', 'Use the assisted dip machine with an upright torso to focus on the triceps rather than the chest. Select your counterweight and perform dips, keeping elbows tucked and body vertical.', 'Machine', ARRAY['Chest','Shoulders'], 'push', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Bar Pushdown', 'Triceps', 'Attach a straight bar to a high cable. Push down to full arm extension, squeezing the triceps. Keep your elbows pinned to your sides throughout. The straight bar allows heavier loads than a rope.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('V-Bar Pushdown', 'Triceps', 'Attach a V-bar to a high cable. Push down to full extension with a neutral grip. The V-bar is easier on the wrists than a straight bar and allows a strong contraction at the bottom.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Reverse-Grip Pushdown', 'Triceps', 'Attach a straight bar to a high cable. Grip underhand (supinated) and push down to full extension. The reverse grip emphasizes the medial head of the tricep. Keep elbows pinned.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Tricep Kickback', 'Triceps', 'Set a cable low. Hinge forward and extend one arm back to lockout behind you. Squeeze the tricep hard at full extension. The cable provides tension throughout, unlike the dumbbell version.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Low Cable Tricep Extension', 'Triceps', 'Face away from a low cable with a rope or handle overhead. Extend your arms overhead by straightening at the elbows. This overhead angle provides a deep stretch on the long head of the tricep.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Skull Crusher', 'Triceps', 'Lie on a bench with your head toward a low cable. Hold a straight bar or EZ bar attachment overhead. Lower toward your forehead by bending at the elbows, then extend. The cable keeps tension constant.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Tricep-Focused Close-Grip Push-Up', 'Triceps', 'Place hands directly under your shoulders or narrower. Perform push-ups with elbows tucked tightly to your sides. This variation places maximum emphasis on the triceps rather than the chest.', 'Bodyweight', ARRAY['Chest','Core'], 'push', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Weighted Dip', 'Triceps', 'Attach a weight belt or hold a dumbbell between your feet. Perform dips with an upright torso, keeping elbows tucked. The added weight builds serious tricep mass and pressing strength.', 'Bodyweight', ARRAY['Chest','Shoulders'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Korean Dip', 'Triceps', 'Sit on a dip bar or ledge with your hands behind you. Dip down and back by bending the elbows, then press back up. This places the triceps in a deep stretch under load. Requires good shoulder mobility.', 'Bodyweight', ARRAY['Shoulders'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- QUADS (~30 new exercises)
-- ============================================================

-- Barbell
('Pause Squat', 'Quads', 'Perform a barbell back squat but pause for 2-3 seconds at the bottom position. Maintain tension and brace hard through the pause. Drive up explosively. The pause eliminates the stretch reflex, building raw quad strength.', 'Barbell', ARRAY['Glutes','Hamstrings','Core'], 'squat', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Tempo Squat', 'Quads', 'Perform a barbell back squat with a slow, controlled descent (3-4 seconds down). The extended time under tension increases muscle damage and growth stimulus. Use lighter weight than regular squats.', 'Barbell', ARRAY['Glutes','Hamstrings','Core'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Wide-Stance Squat', 'Quads', 'Set up for a back squat with feet significantly wider than shoulder-width. Squat to depth, keeping knees tracking over toes. The wide stance increases adductor and glute involvement alongside the quads.', 'Barbell', ARRAY['Glutes','Hamstrings','Core'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Narrow-Stance Squat', 'Quads', 'Perform a back squat with feet hip-width or narrower. Squat to depth with knees pushing forward. The narrow stance increases quad dominance by requiring more knee flexion.', 'Barbell', ARRAY['Glutes','Hamstrings','Core'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Overhead Squat', 'Quads', 'Hold a barbell overhead with a wide snatch grip. Squat to full depth while keeping the bar balanced overhead. This demands exceptional shoulder and ankle mobility and full-body stability.', 'Barbell', ARRAY['Shoulders','Core','Glutes'], 'squat', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Zercher Squat', 'Quads', 'Hold the barbell in the crooks of your elbows. Squat to depth while keeping an upright torso. The front-loaded position heavily taxes the quads and core. Use a pad on the bar for comfort.', 'Barbell', ARRAY['Core','Glutes','Biceps'], 'squat', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Anderson Squat', 'Quads', 'Set the barbell on safety pins at the bottom of your squat depth. Start each rep from a dead stop at the bottom. Press up to standing, then lower back to the pins. This builds explosive power out of the hole.', 'Barbell', ARRAY['Glutes','Hamstrings','Core'], 'squat', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Dumbbell Front Squat', 'Quads', 'Hold dumbbells at your shoulders in a front-rack position. Squat to depth with an upright torso. The front load emphasizes the quads and demands core bracing. Drive through the heels to stand.', 'Dumbbell', ARRAY['Core','Glutes'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Split Squat', 'Quads', 'Stand in a split stance with one foot forward. Hold dumbbells at your sides. Lower your rear knee toward the floor, then press back up through the front foot. Keep your torso upright throughout.', 'Dumbbell', ARRAY['Glutes','Hamstrings'], 'lunge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Curtsy Lunge', 'Quads', 'Hold dumbbells at your sides. Step one foot behind and across your body, as if curtsying. Lower your rear knee toward the floor, then drive back up. This targets the quads and glutes with an adductor component.', 'Dumbbell', ARRAY['Glutes','Core'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Lateral Lunge', 'Quads', 'Hold dumbbells at your sides. Step wide to one side, pushing your hips back and bending the working knee. Keep the trailing leg straight. Push off to return. This trains frontal-plane strength.', 'Dumbbell', ARRAY['Glutes','Hamstrings'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell High Box Step-Up', 'Quads', 'Stand facing a box at or above knee height holding dumbbells. Step up driving through the working leg. The higher the box, the greater the quad and glute demand. Avoid pushing off with the trailing leg.', 'Dumbbell', ARRAY['Glutes','Hamstrings'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Jump Squat', 'Quads', 'Hold light dumbbells at your sides. Squat down, then jump explosively. Land softly and immediately descend into the next rep. This builds explosive quad power and trains fast-twitch fibres.', 'Dumbbell', ARRAY['Glutes','Calves'], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Pendulum Squat', 'Quads', 'Stand in the pendulum squat machine with your back against the pad. Squat to depth as the machine swings along its arc. The unique resistance curve maximizes quad tension at the bottom.', 'Machine', ARRAY['Glutes'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Smith Machine Squat', 'Quads', 'Stand under the Smith machine bar across your traps. Squat to depth with the guided bar path. The fixed path allows you to place your feet forward, increasing quad emphasis.', 'Machine', ARRAY['Glutes','Hamstrings'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Smith Machine Split Squat', 'Quads', 'Stand in a split stance under the Smith machine. Lower your rear knee toward the floor and press back up. The fixed bar path lets you load heavier than free-weight split squats.', 'Machine', ARRAY['Glutes','Hamstrings'], 'lunge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Smith Machine Front Squat', 'Quads', 'Position the Smith machine bar across your front delts. Squat to depth with an upright torso. The guided path removes the balance challenge of a free-weight front squat.', 'Machine', ARRAY['Core','Glutes'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('V-Squat Machine', 'Quads', 'Stand in the V-squat machine facing the pad. Squat to depth as the platform moves along a V-shaped track. This machine targets the quads heavily with reduced spinal loading.', 'Machine', ARRAY['Glutes','Hamstrings'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Leg Press (Wide Stance)', 'Quads', 'Sit in the leg press with feet placed wide and high on the platform. Press to near-lockout. The wide stance increases adductor and glute involvement alongside the quads.', 'Machine', ARRAY['Glutes','Hamstrings'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Leg Press (Narrow Stance)', 'Quads', 'Sit in the leg press with feet placed close together and low on the platform. Press to near-lockout. The narrow, low position maximizes quad engagement by increasing knee flexion.', 'Machine', ARRAY['Glutes'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Belt Squat', 'Quads', 'Attach a belt squat machine belt around your hips. Squat to depth with the load hanging from your hips rather than your shoulders. This eliminates spinal compression while heavily loading the quads.', 'Machine', ARRAY['Glutes','Hamstrings'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Cable Squat', 'Quads', 'Face a low cable with a rope or handle. Hold the attachment at chest height and squat, using the cable as a counterbalance. This is great for teaching squat mechanics and maintaining an upright torso.', 'Cable', ARRAY['Glutes','Core'], 'squat', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Split Squat', 'Quads', 'Stand in a split stance facing a cable machine holding a handle at chest height. Lower into a split squat with constant cable tension. The cable provides a unique resistance angle.', 'Cable', ARRAY['Glutes','Core'], 'lunge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Front Squat', 'Quads', 'Attach a straight bar to a low cable. Hold at chest height and squat with an upright torso. The cable pulls you forward, forcing your quads and core to work harder to stay upright.', 'Cable', ARRAY['Core','Glutes'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Jump Squat', 'Quads', 'Stand with feet shoulder-width apart. Squat down, then jump as high as possible. Land softly with bent knees and immediately descend into the next rep. Great for explosive leg power.', 'Bodyweight', ARRAY['Glutes','Calves'], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Split Jump', 'Quads', 'Start in a lunge position. Jump explosively and switch legs mid-air, landing in a lunge on the opposite side. Continue alternating. This builds single-leg explosive power and coordination.', 'Bodyweight', ARRAY['Glutes','Hamstrings'], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Broad Jump', 'Quads', 'Stand with feet hip-width. Swing your arms back, then explosively jump forward as far as possible. Land softly with bent knees. Reset and repeat. This builds horizontal explosive power.', 'Bodyweight', ARRAY['Glutes','Hamstrings','Calves'], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cossack Squat', 'Quads', 'Stand with feet wide apart. Shift your weight to one side and squat deep on that leg while keeping the other leg straight. Alternate sides. This builds single-leg strength and hip mobility.', 'Bodyweight', ARRAY['Glutes','Hamstrings'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Shrimp Squat', 'Quads', 'Stand on one leg and grab the other foot behind you. Squat down on the standing leg until the rear knee touches the floor. Press back up. This is a challenging single-leg quad exercise.', 'Bodyweight', ARRAY['Glutes','Core'], 'squat', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- HAMSTRINGS (~25 new exercises)
-- ============================================================

-- Barbell
('Stiff-Leg Deadlift (Wide Stance)', 'Hamstrings', 'Stand with a wider-than-shoulder-width stance. Hinge at the hips with stiff legs, lowering the barbell toward the floor. The wide stance increases inner hamstring and adductor engagement. Stand tall at the top.', 'Barbell', ARRAY['Glutes','Back','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Sumo Stiff-Leg Deadlift', 'Hamstrings', 'Stand in a sumo stance with toes turned out. Hinge at the hips with minimal knee bend, lowering the barbell. This targets the inner hamstrings and adductors more than a conventional stance.', 'Barbell', ARRAY['Glutes','Back','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Good Morning (Wide Stance)', 'Hamstrings', 'Stand with a barbell across your traps and feet wider than shoulder-width. Hinge at the hips, pushing them back until your torso is near parallel. Stand tall by driving the hips forward. The wide stance shifts work to the adductors and inner hamstrings.', 'Barbell', ARRAY['Glutes','Back','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Dumbbell Lying Leg Curl', 'Hamstrings', 'Lie face-down on a bench with a dumbbell between your feet. Curl the dumbbell toward your glutes by bending at the knees. Squeeze the hamstrings at the top and lower under control.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Sumo Romanian Deadlift', 'Hamstrings', 'Hold a dumbbell with both hands between your legs in a wide sumo stance. Hinge at the hips with a slight knee bend, lowering the dumbbell toward the floor. Squeeze the hamstrings and glutes to stand.', 'Dumbbell', ARRAY['Glutes','Back'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Single-Leg Deadlift', 'Hamstrings', 'Hold a dumbbell in one hand. Hinge at the hips on the opposite leg, extending the free leg behind you for balance. Lower until your torso is parallel, then stand. This builds unilateral hamstring strength and balance.', 'Dumbbell', ARRAY['Glutes','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Good Morning', 'Hamstrings', 'Hold a dumbbell at your chest or behind your head. Hinge at the hips, pushing them back until your torso is near parallel. Stand by driving the hips forward. The dumbbell version is lighter and more accessible.', 'Dumbbell', ARRAY['Glutes','Back','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Machine Lying Leg Curl', 'Hamstrings', 'Lie face-down on a leg curl machine with the pad behind your ankles. Curl your heels toward your glutes, squeezing the hamstrings at the top. Lower under control. Avoid lifting your hips off the pad.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Machine Seated Leg Curl', 'Hamstrings', 'Sit in a seated leg curl machine with the pad in front of your lower shins. Curl your heels under the seat, squeezing the hamstrings. The seated position provides a greater hamstring stretch.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Machine Standing Leg Curl', 'Hamstrings', 'Stand at a single-leg curl machine with the pad behind one ankle. Curl your heel toward your glute, squeezing the hamstring at the top. Lower under control. Complete all reps on one side before switching.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Glute-Ham Developer (GHD)', 'Hamstrings', 'Set up in a GHD machine with your feet locked in. Lower your torso forward by extending at the knees, then pull yourself back up using your hamstrings. This eccentric-concentric motion is extremely effective for hamstring strength.', 'Machine', ARRAY['Glutes','Core'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Nordic Hamstring Machine', 'Hamstrings', 'Kneel in a nordic curl machine with your ankles locked. Slowly lower your torso forward under control, resisting gravity with your hamstrings. Push off lightly at the bottom if needed and pull yourself back up.', 'Machine', ARRAY['Glutes'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Cable Romanian Deadlift', 'Hamstrings', 'Attach a straight bar to a low cable. Hinge at the hips with a slight knee bend, lowering the bar along your legs. Stand by driving hips forward. The cable provides constant tension, especially at the top.', 'Cable', ARRAY['Glutes','Back'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Leg Curl', 'Hamstrings', 'Attach an ankle strap to a low cable. Stand facing the machine and curl one heel toward your glute. Squeeze the hamstring at the top. Lower under control. Complete all reps on one side.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Single-Leg Curl', 'Hamstrings', 'Attach an ankle strap to a low cable. Lie face-down on a bench and curl one leg at a time. The cable provides constant tension throughout the range of motion, unlike machines.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Standing Cable Hamstring Curl', 'Hamstrings', 'Attach an ankle strap to a low cable. Stand facing the machine, holding something for balance. Curl your heel toward your glute against the cable resistance. This is a simple, effective isolation exercise.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Single-Leg Hip Hinge', 'Hamstrings', 'Stand on one leg. Hinge at the hips, reaching your free leg behind you and your hands toward the floor. Return to standing by driving your hips forward. This builds hamstring flexibility and single-leg stability.', 'Bodyweight', ARRAY['Glutes','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Natural Glute-Ham Raise', 'Hamstrings', 'Kneel with your ankles secured. Slowly lower your torso forward under control using only your hamstrings to resist gravity. At the bottom, push off lightly and use your hamstrings to pull yourself back up.', 'Bodyweight', ARRAY['Glutes','Core'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Stability Ball Hamstring Curl', 'Hamstrings', 'Lie on your back with heels on a stability ball. Lift your hips into a bridge. Curl the ball toward your glutes by bending your knees, then extend back out. Keep your hips elevated throughout.', 'Bodyweight', ARRAY['Glutes','Core'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Nordic Curl (Bodyweight)', 'Hamstrings', 'Kneel on a pad with your ankles secured by a partner or under a heavy object. Slowly lower your torso forward, resisting gravity with your hamstrings. Use a light push-up at the bottom to assist the return.', 'Bodyweight', ARRAY['Glutes','Core'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- GLUTES (~25 new exercises)
-- ============================================================

-- Barbell
('Barbell Sumo Deadlift', 'Glutes', 'Stand with a wide stance and toes turned out. Grip the barbell between your legs. Drive through the floor, pushing knees out and squeezing glutes at lockout. The sumo stance emphasizes glute and adductor engagement.', 'Barbell', ARRAY['Hamstrings','Quads','Back','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Step-Up', 'Glutes', 'Hold a barbell across your traps. Step onto a box at knee height, driving through the working leg. Stand tall on the box, then step back down. The barbell allows heavier loading than dumbbells.', 'Barbell', ARRAY['Quads','Hamstrings'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Pause Hip Thrust', 'Glutes', 'Set up for a barbell hip thrust with your upper back on a bench. Thrust up and pause for 2-3 seconds at the top, squeezing the glutes hard. Lower with control. The pause increases time under tension at peak contraction.', 'Barbell', ARRAY['Hamstrings','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Tempo Hip Thrust', 'Glutes', 'Perform a barbell hip thrust with a 3-4 second lowering phase. The slow eccentric increases time under tension and muscle damage. Thrust up explosively, then lower slowly.', 'Barbell', ARRAY['Hamstrings','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Dumbbell Hip Thrust', 'Glutes', 'Sit on the floor with your upper back against a bench and a dumbbell on your hips. Thrust your hips up, squeezing the glutes at the top. Lower with control. The dumbbell version is more accessible than barbell.', 'Dumbbell', ARRAY['Hamstrings','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Single-Leg Hip Thrust', 'Glutes', 'Set up for a hip thrust with one foot planted and the other raised. Hold a dumbbell on the working hip. Thrust up on one leg, squeezing the glute at the top. This addresses imbalances between sides.', 'Dumbbell', ARRAY['Hamstrings','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Donkey Kick', 'Glutes', 'Get on all fours and place a light dumbbell behind one knee. Kick that leg back and up, squeezing the glute at the top. Lower with control. Keep your core braced and avoid arching your back.', 'Dumbbell', ARRAY['Hamstrings'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Lateral Lunge (Glute Focus)', 'Glutes', 'Hold dumbbells at your sides. Step wide to one side, sitting your hips back into the working leg. Push your butt back to emphasize glute loading. Drive back to standing through the working heel.', 'Dumbbell', ARRAY['Quads','Hamstrings'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Step-Up (Glute Focus)', 'Glutes', 'Stand facing a box at or above knee height holding dumbbells. Step up, leaning your torso slightly forward to emphasize glute engagement. Drive through the heel of the working leg. Avoid pushing off the back foot.', 'Dumbbell', ARRAY['Quads','Hamstrings'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Curtsy Lunge (Glute Focus)', 'Glutes', 'Hold dumbbells at your sides. Step one foot behind and across your body into a curtsy. Lower your rear knee toward the floor, feeling a deep stretch in the glute of the front leg. Drive back up through the front heel.', 'Dumbbell', ARRAY['Quads','Core'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Machine / Cable
('Machine Hip Thrust', 'Glutes', 'Use a dedicated hip thrust machine. Set up with your upper back against the pad and feet planted. Thrust up, squeezing the glutes hard at the top. Lower under control. The machine makes loading and setup easy.', 'Machine', ARRAY['Hamstrings','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Seated Hip Abduction Machine', 'Glutes', 'Sit in the hip abduction machine with pads against your outer thighs. Push your legs apart against the resistance, squeezing the glute medius at the end range. Return slowly.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Standing Hip Abduction Machine', 'Glutes', 'Stand in a cable or machine station with a pad against your outer ankle. Push your leg out to the side against the resistance, squeezing the glute medius. Return under control. Complete all reps on one side.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Hip Adduction Machine', 'Glutes', 'Sit in the hip adduction machine with pads against your inner thighs. Squeeze your legs together against the resistance. Return slowly. This targets the adductors and inner glutes.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Glute Kickback', 'Glutes', 'Attach an ankle strap to a low cable. Face the machine and kick one leg straight back, squeezing the glute at the top. Lower under control. Keep your core braced and avoid arching your back.', 'Cable', ARRAY['Hamstrings'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Hip Abduction', 'Glutes', 'Attach an ankle strap to a low cable. Stand sideways to the machine and push the outside leg away from the cable. Squeeze the glute medius at the end range. Return under control.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Pull-Through (Glute Focus)', 'Glutes', 'Stand facing away from a low cable with a rope between your legs. Hinge at the hips, letting the rope pull through. Drive your hips forward to stand, squeezing the glutes hard at the top.', 'Cable', ARRAY['Hamstrings','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Donkey Kick', 'Glutes', 'Attach an ankle strap to a low cable. Get on all fours facing the machine. Kick one leg back and up against the cable resistance. Squeeze the glute at the top. Lower under control.', 'Cable', ARRAY['Hamstrings'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Hip Thrust (Bodyweight)', 'Glutes', 'Sit on the floor with your upper back against a bench. Plant your feet and thrust your hips up, squeezing the glutes hard at the top. Lower with control. This is the foundation before adding weight.', 'Bodyweight', ARRAY['Hamstrings','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Single-Leg Hip Thrust (Bodyweight)', 'Glutes', 'Set up for a bodyweight hip thrust. Raise one foot off the floor and thrust up on the planted leg. Squeeze the working glute at the top. This builds single-leg glute strength and reveals imbalances.', 'Bodyweight', ARRAY['Hamstrings','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Glute Bridge March', 'Glutes', 'Lie on your back in a glute bridge position with hips raised. Alternate lifting each foot off the floor in a marching motion while keeping your hips level and elevated. This challenges glute stability and endurance.', 'Bodyweight', ARRAY['Hamstrings','Core'], 'hinge', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Donkey Kick', 'Glutes', 'Get on all fours. Kick one leg back and up toward the ceiling, keeping the knee bent at 90 degrees. Squeeze the glute at the top. Lower with control. Keep your core braced throughout.', 'Bodyweight', ARRAY['Hamstrings'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Fire Hydrant', 'Glutes', 'Get on all fours. Lift one knee out to the side, keeping it bent at 90 degrees. Raise until your thigh is parallel to the floor. Squeeze the glute medius at the top. Lower with control.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- CALVES (~15 new exercises)
-- ============================================================

-- Barbell
('Standing Barbell Calf Raise', 'Calves', 'Place a barbell across your traps. Stand with the balls of your feet on a raised surface. Rise up onto your toes, squeezing the calves at the top. Lower slowly to a full stretch.', 'Barbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Seated Barbell Calf Raise', 'Calves', 'Sit on a bench with a barbell across your knees and the balls of your feet on a raised surface. Raise your heels by pressing through the balls of your feet. This targets the soleus muscle.', 'Barbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Single-Leg Barbell Calf Raise', 'Calves', 'Place a barbell across your traps. Stand on one foot on a raised surface. Rise up onto your toes, squeezing the calf. Lower slowly to a full stretch. The unilateral version addresses imbalances.', 'Barbell', ARRAY[]::text[], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Single-Leg Dumbbell Calf Raise', 'Calves', 'Hold a dumbbell in one hand and stand on one foot on a raised surface. Rise onto your toes, squeezing the calf. Lower to a full stretch. Hold something for balance with the free hand.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Seated Dumbbell Calf Raise', 'Calves', 'Sit on a bench with dumbbells on your knees. Place the balls of your feet on a raised surface. Raise your heels by pressing through the balls of your feet. This targets the soleus.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Standing Dumbbell Calf Raise (Bilateral)', 'Calves', 'Hold dumbbells at your sides and stand with the balls of your feet on a raised surface. Rise onto your toes, squeezing both calves at the top. Lower slowly to a full stretch.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Smith Machine Calf Raise', 'Calves', 'Stand under the Smith machine with the bar across your traps and feet on a raised surface. Rise onto your toes, squeezing the calves. Lower slowly. The machine provides stability for heavier loading.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Hack Squat Calf Raise', 'Calves', 'Stand in a hack squat machine with the balls of your feet at the bottom of the platform. Rise onto your toes, pressing through the balls of your feet. The angled position provides a unique stretch.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Leg Press Calf Raise (Single Leg)', 'Calves', 'Sit in a leg press machine with one foot on the bottom of the platform. Press through the ball of your foot to extend your ankle. Lower slowly. Complete all reps on one side before switching.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Cable Calf Raise', 'Calves', 'Attach a belt or hold a cable handle at your hips. Stand on a raised surface and rise onto your toes against the cable resistance. The cable provides smooth, constant tension.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Single-Leg Cable Calf Raise', 'Calves', 'Attach an ankle strap or hold a handle. Stand on one foot on a raised surface and rise onto your toes against the cable resistance. The unilateral approach addresses calf imbalances.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Single-Leg Calf Raise (Bodyweight)', 'Calves', 'Stand on one foot on a raised surface. Rise onto your toes, squeezing the calf at the top. Lower slowly past the edge for a full stretch. Hold something for balance. This is a simple but effective calf builder.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Explosive Calf Raise', 'Calves', 'Stand on a raised surface and explosively rise onto your toes, briefly leaving the surface. Land softly and immediately repeat. This trains the fast-twitch calf fibres for power and explosiveness.', 'Bodyweight', ARRAY[]::text[], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Seated Bodyweight Calf Raise', 'Calves', 'Sit on a bench with your feet flat on the floor. Place a weight plate on your knees if desired, or use just bodyweight. Raise your heels by pressing through the balls of your feet. This targets the soleus.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Wall Calf Raise', 'Calves', 'Stand facing a wall with hands on the wall for balance. Rise onto your toes, squeezing the calves at the top. Lower slowly. The wall provides stability for focusing on the calf contraction.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- CORE (~30 new exercises)
-- ============================================================

-- Barbell
('Barbell Rollout', 'Core', 'Kneel on the floor with a barbell loaded with round plates. Roll the bar forward by extending your arms and body, then pull back to the starting position using your core. Avoid letting your hips sag.', 'Barbell', ARRAY['Shoulders'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Landmine Twist', 'Core', 'Hold the end of a landmine barbell at chest height with both hands. Rotate from side to side, lowering the bar in an arc to each hip. Keep your arms extended and rotate through the torso.', 'Barbell', ARRAY['Shoulders'], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Sit-Up', 'Core', 'Lie on your back holding a barbell at arm''s length above your chest. Sit up while keeping the bar pressed overhead. Lower back down with control. The weight overhead increases core demand significantly.', 'Barbell', ARRAY['Shoulders'], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Loaded Barbell Carry', 'Core', 'Hold a barbell in a front rack, overhead, or zercher position. Walk for the prescribed distance. The unstable bar challenges core stability far more than dumbbells. Keep your core braced and walk with controlled steps.', 'Barbell', ARRAY['Shoulders','Back'], 'carry', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Dumbbell
('Dumbbell Woodchop', 'Core', 'Hold a dumbbell with both hands. Start at one hip and rotate diagonally upward to the opposite shoulder, pivoting your feet. Control the return. This trains rotational power through the core.', 'Dumbbell', ARRAY['Shoulders'], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Side Bend', 'Core', 'Hold a dumbbell in one hand at your side. Bend laterally away from the weight, then return to upright. Complete all reps on one side before switching. This targets the obliques directly.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Weighted Crunch', 'Core', 'Lie on your back holding a dumbbell or plate on your chest. Crunch up, lifting your shoulder blades off the floor. Squeeze your abs at the top and lower with control.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Dead Bug', 'Core', 'Lie on your back holding a dumbbell in each hand above your chest. Extend opposite arm and leg toward the floor while keeping your lower back pressed into the floor. Return and alternate sides.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Sit-Up', 'Core', 'Lie on your back holding a dumbbell at your chest. Sit all the way up, keeping the weight at your chest. Lower with control. The added weight increases the demand on your hip flexors and abs.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Weighted Russian Twist', 'Core', 'Sit with knees bent and feet off the floor, holding a dumbbell or plate. Rotate your torso side to side, touching the weight to the floor on each side. Keep your chest up and core tight throughout.', 'Dumbbell', ARRAY[]::text[], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Oblique Crunch', 'Core', 'Lie on your side with a dumbbell held at your temple. Crunch sideways, lifting your torso toward your hip. Squeeze the oblique at the top and lower with control. Complete all reps on one side.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Machine
('Ab Crunch Machine', 'Core', 'Sit in the ab crunch machine with your feet under the pads and hands on the handles. Crunch forward, flexing your spine and squeezing the abs. Return under control. Avoid using your arms to pull.', 'Machine', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Rotary Torso Machine', 'Core', 'Sit in the rotary torso machine with the pad against your torso. Rotate to one side against the resistance, engaging the obliques. Return under control. Complete all reps on one side before switching.', 'Machine', ARRAY[]::text[], 'rotation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Decline Sit-Up (Bench)', 'Core', 'Lie on a decline bench with your feet secured at the top. Perform a full sit-up, bringing your torso to your knees. Lower with control. The decline angle increases gravity''s pull, making the movement harder.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Captain''s Chair Leg Raise', 'Core', 'Support yourself in a captain''s chair with your forearms on the pads. Raise your legs to hip height or higher, keeping them straight. Lower under control. Avoid swinging — use your abs to lift.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Roman Chair Sit-Up', 'Core', 'Set up in a roman chair (back hyperextension bench) facing up. Lower your torso backward past horizontal, then sit back up using your core. The extended range of motion increases demand on the abs.', 'Machine', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Cable
('Cable Woodchop (High-to-Low)', 'Core', 'Set a cable high. Stand sideways and pull the handle diagonally down and across your body. Rotate through your torso, keeping arms extended. This trains anti-rotation and rotational power.', 'Cable', ARRAY['Shoulders'], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Woodchop (Low-to-High)', 'Core', 'Set a cable low. Stand sideways and pull the handle diagonally up and across your body. Rotate through your torso with extended arms. This is the reverse direction of the high-to-low chop.', 'Cable', ARRAY['Shoulders'], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Oblique Crunch', 'Core', 'Attach a handle to a high cable. Stand sideways and crunch laterally, pulling the handle down toward the outside hip. This directly targets the obliques with constant cable tension.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Anti-Rotation Press', 'Core', 'Set a cable at chest height. Stand sideways and hold the handle at your chest. Press the handle straight out in front of you and hold, resisting the cable''s pull to rotate you. This builds anti-rotation core strength.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Bodyweight
('Hollow Body Hold', 'Core', 'Lie on your back. Lift your shoulders and legs off the floor, creating a "hollow" position with arms extended overhead. Hold for time. Keep your lower back pressed into the floor throughout.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Tuck Crunch', 'Core', 'Lie on your back. Simultaneously bring your knees to your chest and crunch your upper body toward your knees. Squeeze the abs at the peak, then extend back out. Avoid resting between reps.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Toe Touch Crunch', 'Core', 'Lie on your back with legs raised straight toward the ceiling. Crunch up and reach your hands toward your toes. Lower your shoulders back to the floor. Keep your legs vertical throughout.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Plank Shoulder Tap', 'Core', 'Hold a high plank position. Lift one hand and tap the opposite shoulder, then switch. Keep your hips level and avoid rocking side to side. This challenges anti-rotation stability.', 'Bodyweight', ARRAY['Shoulders'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Plank Hip Dip', 'Core', 'Hold a forearm plank. Rotate your hips to one side, dipping toward the floor, then rotate to the other side. This dynamic plank variation targets the obliques and builds rotational endurance.', 'Bodyweight', ARRAY[]::text[], 'rotation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Reverse Crunch', 'Core', 'Lie on your back with hands at your sides. Curl your knees toward your chest, lifting your hips off the floor. Lower with control. Focus on using the lower abs to lift your hips rather than swinging.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Spiderman Plank', 'Core', 'Hold a high plank position. Bring one knee toward the same-side elbow by rotating your hip outward. Return and alternate sides. This adds a hip flexor and oblique component to the standard plank.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Decline Crunch', 'Core', 'Lie on a decline bench with your feet secured. Crunch up, lifting your shoulder blades off the bench. Squeeze the abs and lower with control. The decline angle adds resistance through gravity.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('GHD Sit-Up', 'Core', 'Sit in a GHD machine with your feet locked. Lower your torso back past parallel, then sit up explosively using your abs and hip flexors. Touch the floor behind you for full range. Be cautious — this is intense.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Copenhagen Side Plank', 'Core', 'Lie on your side with your top foot on an elevated surface and your bottom leg hanging. Hold a side plank by engaging your obliques and adductors. This builds lateral core and inner thigh strength simultaneously.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- FOREARMS (~15 new exercises)
-- ============================================================

('Wrist Curl (Dumbbell)', 'Forearms', 'Sit with forearms on your thighs, palms up, holding dumbbells. Curl your wrists upward, squeezing the forearm flexors at the top. Lower slowly. This directly targets the wrist flexors.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Reverse Wrist Curl (Dumbbell)', 'Forearms', 'Sit with forearms on your thighs, palms down, holding dumbbells. Extend your wrists upward. Lower slowly. This targets the wrist extensors on the back of the forearm.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Behind-the-Back Barbell Wrist Curl', 'Forearms', 'Stand holding a barbell behind your back with an underhand grip. Curl your wrists upward, squeezing the forearm flexors. Lower under control. The behind-the-back position allows a natural wrist path.', 'Barbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Farmer''s Walk (Heavy)', 'Forearms', 'Pick up the heaviest dumbbells or farmer''s handles you can hold. Walk for the prescribed distance or time. Your grip will be the limiting factor. Keep shoulders packed and core braced throughout.', 'Dumbbell', ARRAY['Core','Back','Shoulders'], 'carry', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Plate Pinch Carry', 'Forearms', 'Pinch two weight plates together smooth-side-out between your thumb and fingers. Walk for distance or hold for time. This specifically targets the thumb and finger pinch grip strength.', 'Bodyweight', ARRAY[]::text[], 'carry', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Towel Pull-Up', 'Forearms', 'Drape two towels over a pull-up bar and grip one in each hand. Perform pull-ups while holding the towels. The thick, unstable grip forces your forearms to work much harder.', 'Bodyweight', ARRAY['Back','Biceps'], 'pull', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Dead Hang', 'Forearms', 'Hang from a pull-up bar with an overhand grip and arms fully extended. Hold for as long as possible. This builds grip endurance and decompresses the spine. Keep shoulders engaged, not shrugged to ears.', 'Bodyweight', ARRAY['Back','Shoulders'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Fat Grip Barbell Curl', 'Forearms', 'Wrap Fat Gripz around a barbell and perform curls. The thicker bar forces your forearms to work harder to maintain grip throughout the curl. Use less weight than standard curls.', 'Barbell', ARRAY['Biceps'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Wrist Curl', 'Forearms', 'Sit with forearms on your thighs, palms up, holding a cable handle attached to a low pulley. Curl your wrists upward against the constant cable tension. Lower slowly.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Reverse Wrist Curl', 'Forearms', 'Sit with forearms on your thighs, palms down, holding a cable handle attached to a low pulley. Extend your wrists upward against the cable tension. Lower slowly.', 'Cable', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Wrist Roller (Cable)', 'Forearms', 'Attach a wrist roller to a cable machine. Roll the handle forward and backward by rotating your wrists. This continuous motion builds forearm endurance and strength through a full range.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Hammer Curl (Forearm Focus)', 'Forearms', 'Perform hammer curls with a slow, controlled tempo and a focus on the forearm contraction. The neutral grip heavily loads the brachioradialis. Squeeze at the top and lower over 3 seconds.', 'Dumbbell', ARRAY['Biceps'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Finger Curl', 'Forearms', 'Hold a barbell with an overhand grip and let it roll down to your fingertips. Curl your fingers to roll the bar back into your palm. This targets finger flexor strength directly.', 'Barbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Kettlebell Bottom-Up Press', 'Forearms', 'Hold a kettlebell upside-down (bottom up) at shoulder height. Press it overhead while maintaining balance. The unstable load demands intense forearm and grip activation throughout. Use light weight.', 'Kettlebell', ARRAY['Shoulders','Core'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Resistance Band Wrist Extension', 'Forearms', 'Wrap a resistance band around your fingers with your forearm resting on a surface, palm down. Extend your fingers and wrist against the band resistance. This prehab exercise prevents forearm imbalances.', 'Resistance Band', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- ============================================================
-- ADDITIONAL EXERCISES TO REACH 320+
-- ============================================================

-- Additional Chest
('Flat Dumbbell Squeeze Press', 'Chest', 'Lie flat pressing two dumbbells together forcefully throughout the movement. The inward squeezing force maximizes inner chest activation. Press to lockout while maintaining the squeeze.', 'Dumbbell', ARRAY['Triceps'], 'push', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Svend Press', 'Chest', 'Stand holding a weight plate between your palms at chest height. Press the plate forward while squeezing your hands together. Return to your chest. The constant squeeze targets the inner chest.', 'Bodyweight', ARRAY['Shoulders'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Back
('Meadows Row (Dumbbell)', 'Back', 'Hinge forward with one arm supported on a bench. Row a heavy dumbbell to your hip with an overhand grip, pulling in an arc. This variation named after John Meadows emphasizes the lower lats.', 'Dumbbell', ARRAY['Biceps','Shoulders'], 'pull', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Kayak Row', 'Back', 'Sit on the floor with legs extended holding a barbell at one end. Row the barbell alternating from one side to the other like paddling a kayak. This targets the lats and obliques simultaneously.', 'Barbell', ARRAY['Core','Biceps'], 'pull', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Prone Incline Dumbbell Shrug', 'Back', 'Lie face-down on an incline bench. Hold dumbbells and shrug your shoulders up and back, squeezing the middle traps. The incline position changes the resistance angle and eliminates momentum.', 'Dumbbell', ARRAY['Shoulders'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Shoulders
('Lu Raise', 'Shoulders', 'Hold light dumbbells with a pronated grip. Perform a lateral raise to shoulder height, then transition to a front press overhead. Lower through the reverse path. This combines lateral raises and presses in one movement.', 'Dumbbell', ARRAY['Triceps'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Bradford Press', 'Shoulders', 'Start with a barbell at your front delts. Press it just high enough to clear your head, then lower behind your neck. Press again over your head to the front. Each front-to-back cycle is one rep. Use light weight.', 'Barbell', ARRAY['Triceps'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Lateral Raise (Leaning)', 'Shoulders', 'Hold a pole or rack with one hand and lean away from it. Perform lateral raises with the other arm. The lean increases the range of motion and keeps tension on the lateral delt through the full arc.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Plate Front Raise', 'Shoulders', 'Hold a weight plate with both hands at waist height. Raise it to eye level with straight arms. Lower under control. The plate grip forces engagement of the forearms alongside the front delts.', 'Bodyweight', ARRAY['Core','Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Biceps
('Waiter Curl', 'Biceps', 'Hold one end of a dumbbell vertically with both hands cupped under the plate, like a waiter holding a tray. Curl up, keeping elbows pinned to your sides. This uniquely loads the short head of the bicep.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('21s Barbell Curl', 'Biceps', 'Perform 7 partial curls in the bottom half of the range, 7 in the top half, then 7 full-range curls. The continuous tension and metabolic stress make this an intense bicep finisher.', 'Barbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Incline Hammer Curl', 'Biceps', 'Sit on an incline bench with dumbbells at your sides, palms facing in. Curl with a hammer grip. The incline puts the biceps in a stretched position at the start, increasing long head activation.', 'Dumbbell', ARRAY['Forearms'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Triceps
('Overhead EZ Bar Tricep Extension', 'Triceps', 'Stand holding an EZ bar overhead with a close grip. Lower the bar behind your head by bending at the elbows. Extend back to lockout. The EZ bar is easier on the wrists than a straight bar.', 'Barbell', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell JM Press', 'Triceps', 'Lie on a bench with dumbbells. Lower them toward your chin/upper chest by bending at the elbows, then press up. This hybrid of a close-grip press and skull crusher is a powerful tricep builder.', 'Dumbbell', ARRAY['Chest'], 'push', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Bodyweight Tricep Extension', 'Triceps', 'Set a bar at hip height in a rack. Grip it with hands close together and lean forward. Lower your head under the bar by bending at the elbows, then press back up. Like a skull crusher using bodyweight.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Quads
('Depth Jump', 'Quads', 'Stand on a box. Step off the edge (don''t jump), land softly, and immediately jump vertically as high as possible. The drop increases the eccentric load, training reactive strength and fast-twitch fibres.', 'Bodyweight', ARRAY['Glutes','Calves'], 'plyometric', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Heel-Elevated Squat', 'Quads', 'Place your heels on a small wedge or plates while performing a barbell squat. The heel elevation allows greater knee travel forward, dramatically increasing quad activation. Keep torso upright.', 'Barbell', ARRAY['Glutes','Core'], 'squat', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Hamstrings
('Kettlebell Swing (Single-Arm)', 'Hamstrings', 'Perform a kettlebell swing using one arm. The unilateral loading challenges your core anti-rotation while still driving the movement through hip extension. Switch arms each set.', 'Kettlebell', ARRAY['Glutes','Core','Back'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Band-Assisted Nordic Curl', 'Hamstrings', 'Kneel with ankles secured and a resistance band attached overhead for assistance. Slowly lower your torso forward, using the band to assist through the hardest portion. This is a progression toward full nordics.', 'Resistance Band', ARRAY['Glutes','Core'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Deficit Romanian Deadlift', 'Hamstrings', 'Stand on a small platform and perform a Romanian deadlift. The extra range of motion from the deficit increases the hamstring stretch at the bottom. Use moderate weight and control the descent.', 'Barbell', ARRAY['Glutes','Back','Core'], 'hinge', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Banded Leg Curl', 'Hamstrings', 'Lie face-down with a resistance band attached to your ankles and a fixed point. Curl your heels toward your glutes against the band tension. The band provides more resistance as you curl further.', 'Resistance Band', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Glutes
('Barbell Donkey Kick', 'Glutes', 'Set up on all fours with a light barbell behind one knee. Kick that leg back and up, squeezing the glute at the top. The barbell adds resistance beyond bodyweight. Use a pad for comfort.', 'Barbell', ARRAY['Hamstrings'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Frog Pump (Weighted)', 'Glutes', 'Lie on your back with soles together and knees out (frog position). Place a dumbbell on your hips. Thrust your hips up, squeezing the glutes. The frog position maximizes glute activation over hamstrings.', 'Dumbbell', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Lateral Band Walk (Heavy)', 'Glutes', 'Place a heavy resistance band around your ankles or above your knees. Stand in a quarter squat and take lateral steps, keeping tension on the band. This targets the glute medius intensely.', 'Resistance Band', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Additional Core
('Stir-the-Pot (Stability Ball)', 'Core', 'Place your forearms on a stability ball in a plank position. Move your forearms in small circles, "stirring the pot." The unstable surface forces deep core muscles to work hard to maintain stability.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Stability Ball Rollout', 'Core', 'Kneel behind a stability ball with forearms on top. Roll the ball forward by extending your arms, then pull back using your core. Similar to an ab wheel but the ball provides a softer learning curve.', 'Bodyweight', ARRAY['Shoulders'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Starfish Crunch', 'Core', 'Lie on your back with arms and legs spread wide forming an X. Crunch up, bringing your right hand to your left foot. Lower and repeat with the opposite hand and foot. Alternate each rep.', 'Bodyweight', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Bear Crawl (Lateral)', 'Core', 'Start on all fours with knees hovering. Move laterally by stepping same-side hand and foot together. Keep hips low and core engaged. This lateral variation challenges stability in the frontal plane.', 'Bodyweight', ARRAY['Shoulders','Quads'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),

-- Full Body additions
('Dumbbell Snatch', 'Full Body', 'Hold a dumbbell between your legs. Explosively extend your hips and pull the dumbbell overhead in one fluid motion, catching it at lockout. Lower with control. This builds total-body power.', 'Dumbbell', ARRAY['Shoulders','Glutes','Hamstrings','Core'], 'compound', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Complex', 'Full Body', 'Perform a sequence of barbell movements without putting the bar down: deadlift, row, clean, front squat, overhead press. One cycle is one rep. This is an intense conditioning and strength-building protocol.', 'Barbell', ARRAY['Shoulders','Back','Quads','Glutes','Core'], 'compound', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Kettlebell Clean', 'Full Body', 'Hinge at the hips and swing a kettlebell between your legs. Explosively extend your hips and guide the bell to a racked position at your shoulder. The clean is a foundational kettlebell movement.', 'Kettlebell', ARRAY['Shoulders','Back','Glutes','Hamstrings','Core'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Kettlebell Snatch', 'Full Body', 'Swing a kettlebell between your legs and explosively drive it overhead in one fluid motion. Punch through at the top to avoid the bell slamming your wrist. This is the king of kettlebell exercises.', 'Kettlebell', ARRAY['Shoulders','Back','Glutes','Hamstrings','Core'], 'compound', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Devil Press', 'Full Body', 'Hold two dumbbells. Perform a burpee with the dumbbells on the floor, then swing the dumbbells from between your legs to overhead in one motion. Lower and repeat. Extremely demanding for conditioning.', 'Dumbbell', ARRAY['Shoulders','Chest','Glutes','Hamstrings','Core'], 'compound', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Wall Ball', 'Full Body', 'Hold a medicine ball at your chest. Squat down, then explosively stand and throw the ball at a wall target above you. Catch it on the rebound and immediately squat again. A staple of functional fitness.', 'Bodyweight', ARRAY['Quads','Glutes','Shoulders','Core'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Sled Drag', 'Full Body', 'Attach a strap to a loaded sled. Walk backward dragging the sled, keeping tension on the strap. This is low-impact and targets the quads, glutes, and cardiovascular system effectively.', 'Sled', ARRAY['Quads','Glutes','Hamstrings','Core'], 'compound', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Rope Climb', 'Full Body', 'Grip a thick rope and climb using your arms and legs. Wrap the rope around one foot for a foothold and drive upward. This builds grip, pulling strength, and total-body coordination.', 'Bodyweight', ARRAY['Back','Biceps','Core','Forearms'], 'pull', 'advanced', false, '00000000-0000-0000-0000-000000000000'),

-- Cardio additions
('Box Jump (Cardio)', 'Cardio', 'Stand facing a plyometric box. Jump onto the box, landing softly with both feet. Stand tall on top, then step down. Repeat for reps or time. Adjust box height to your ability level.', 'Bodyweight', ARRAY['Quads','Glutes','Calves'], 'plyometric', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Sled Push (Cardio)', 'Cardio', 'Load a sled with moderate weight. Push it for the prescribed distance using short, powerful strides. Keep a low body angle and drive through the balls of your feet. Rest and repeat for intervals.', 'Sled', ARRAY['Quads','Glutes','Core'], 'cardio', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Kettlebell Swing (Cardio)', 'Cardio', 'Perform kettlebell swings continuously for timed intervals. Use a moderate weight and focus on hip snap. This is one of the most efficient conditioning exercises, training strength and cardio simultaneously.', 'Kettlebell', ARRAY['Glutes','Hamstrings','Core'], 'cardio', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Rowing Machine (Intervals)', 'Cardio', 'Row at high intensity for 30-60 seconds, then row easy for equal rest. Repeat for the prescribed number of intervals. Focus on driving with the legs first, then opening the hips, then pulling with the arms.', 'Machine', ARRAY['Back','Quads','Core'], 'cardio', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Ski Erg (Intervals)', 'Cardio', 'Use the ski erg for timed intervals. Hinge at the hips and pull both handles down simultaneously, driving with the lats and core. Stand tall between reps. An excellent upper-body cardio tool.', 'Machine', ARRAY['Back','Shoulders','Core'], 'cardio', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Assault Bike (Intervals)', 'Cardio', 'Ride the assault bike at high intensity for short intervals (20-60 seconds). Push and pull with both arms and legs simultaneously. Rest between intervals. The air resistance scales to your effort.', 'Machine', ARRAY['Quads','Shoulders','Core'], 'cardio', 'beginner', false, '00000000-0000-0000-0000-000000000000'),

-- Additional exercises to exceed 320
('Barbell Hang Clean', 'Full Body', 'Start with the barbell at hip height in a hang position. Explosively extend your hips and pull the bar up, dropping under it to catch in a front rack. Stand to complete the rep. A simpler entry point than power cleans from the floor.', 'Barbell', ARRAY['Shoulders','Glutes','Hamstrings','Back','Core'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Renegade Row', 'Full Body', 'Hold two dumbbells in a push-up position. Row one dumbbell to your hip while stabilizing with the other arm, then switch. Add a push-up between rows for more challenge. Keep hips level throughout.', 'Dumbbell', ARRAY['Back','Chest','Core','Biceps'], 'compound', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Trap Bar Carry', 'Full Body', 'Pick up a loaded trap bar and walk for the prescribed distance. The neutral grip and centered load make this a comfortable heavy carry variation. Keep your shoulders packed and core engaged.', 'Barbell', ARRAY['Core','Back','Forearms'], 'carry', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Face Pull (Rear Delt)', 'Shoulders', 'Set a cable at face height with a rope. Pull toward your face while externally rotating your shoulders at the end. Separate the rope ends wide and squeeze the rear delts. Excellent for posture and shoulder health.', 'Cable', ARRAY['Back'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Single-Arm Cable Lateral Raise', 'Shoulders', 'Stand sideways to a low cable holding a handle. Raise your arm out to the side to shoulder height. The cable provides constant tension, especially at the bottom where dumbbells have none.', 'Cable', ARRAY[]::text[], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Pullover (Back Focus)', 'Back', 'Lie across a bench with only your upper back supported. Hold one dumbbell overhead. Lower it behind your head with straight arms, focusing on stretching and squeezing the lats. Pull back over using your back, not chest.', 'Dumbbell', ARRAY['Chest','Core'], 'isolation', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Cable Hip Extension', 'Glutes', 'Attach an ankle strap to a low cable. Face the machine and extend one leg straight behind you, squeezing the glute at full extension. Lower under control. This isolates the glute max through hip extension.', 'Cable', ARRAY['Hamstrings'], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Cable Romanian Deadlift (Glute Focus)', 'Glutes', 'Attach a straight bar to a low cable. Hinge at the hips with slight knee bend, lowering the bar along your legs. Drive hips forward to stand, squeezing glutes hard at lockout. Cable keeps tension constant.', 'Cable', ARRAY['Hamstrings','Back'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Kettlebell Windmill', 'Core', 'Hold a kettlebell overhead with one arm locked out. Hinge at the hip and reach your free hand down your opposite leg, keeping the bell overhead. Stand back up. This builds rotational core stability and shoulder endurance.', 'Kettlebell', ARRAY['Shoulders','Glutes'], 'rotation', 'advanced', false, '00000000-0000-0000-0000-000000000000'),
('Suitcase Deadlift', 'Core', 'Stand next to a barbell or heavy dumbbell on the floor. Deadlift it with one hand, resisting the lateral pull. Walk if desired or just stand and hold. This is one of the best anti-lateral-flexion core exercises.', 'Dumbbell', ARRAY['Back','Glutes','Forearms'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Resistance Band Pallof Press', 'Core', 'Anchor a resistance band at chest height. Hold it at your chest and press straight forward, resisting the band''s pull to rotate you. Hold at full extension, then return. A versatile anti-rotation exercise.', 'Resistance Band', ARRAY[]::text[], 'isolation', 'beginner', false, '00000000-0000-0000-0000-000000000000'),
('Dumbbell Romanian Deadlift (Single-Leg)', 'Hamstrings', 'Hold a dumbbell in one hand. Hinge on the opposite leg, extending your free leg behind you. Lower until your torso is parallel, then stand. This builds hamstring and balance in one movement.', 'Dumbbell', ARRAY['Glutes','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Barbell Hip Thrust (Pause)', 'Glutes', 'Perform a standard barbell hip thrust but hold the top position for 3 seconds on every rep. The extended pause maximizes glute activation and eliminates any momentum from the movement.', 'Barbell', ARRAY['Hamstrings','Core'], 'hinge', 'intermediate', false, '00000000-0000-0000-0000-000000000000'),
('Goblet Curtsy Lunge', 'Quads', 'Hold a dumbbell or kettlebell at your chest in a goblet position. Step one foot behind and across your body. Lower until the rear knee nearly touches the floor. The front-loaded weight keeps your torso upright.', 'Dumbbell', ARRAY['Glutes','Core'], 'lunge', 'intermediate', false, '00000000-0000-0000-0000-000000000000')

ON CONFLICT (name) DO NOTHING;


-- ============================================================
-- VERIFICATION QUERIES
-- Run these after the insert to verify the expansion
-- ============================================================

-- Breakdown by muscle group and equipment
SELECT muscle_group, equipment, COUNT(*) as count
FROM exercises
WHERE equipment IN ('Barbell', 'Dumbbell', 'Machine', 'Cable', 'Bodyweight')
AND muscle_group IN ('Chest', 'Back', 'Shoulders', 'Biceps', 'Triceps', 'Quads', 'Hamstrings', 'Glutes', 'Calves', 'Core')
GROUP BY muscle_group, equipment
ORDER BY muscle_group, equipment;

-- Total exercise count
SELECT COUNT(*) FROM exercises;
